import { test, expect, Page } from '@playwright/test';
import { promises as fs } from 'fs';

const SF_HOME = 'https://www.wikipedia.org';
const STORAGE_STATE = './user.json';

// [AI-SYNTHESIZED] CANDIDATES array for demonstration; not used in this test but included per template
const CANDIDATES = ['Playwright automation'];

async function login(page: Page) {
  // [AI-SYNTHESIZED] Use storageState for authentication/session
  await page.context().addCookies(JSON.parse(await fs.readFile(STORAGE_STATE, 'utf-8')).cookies);
  console.log('[step] ✅ Loaded storage state for login');
}

test.describe('Wikipedia Search and Article Verification', () => {
  test('Searches for Playwright automation and verifies article page', async ({ page }) => {
    // Login helper (not strictly needed for Wikipedia, but included per template)
    await login(page);

    // Step 1: Navigate to Wikipedia home
    await page.goto(SF_HOME);
    await page.waitForLoadState('networkidle');
    console.log('[step] ✅ Navigated to Wikipedia home');

    // Step 2: Locate search box and enter query
    // [AI-HEAL] Use .or() to provide alternative selector chains for dynamic search box
    const searchBox = page.getByRole('searchbox', { name: /search/i })
      .or(() => page.locator('input[name="search"]'))
      .or(() => page.locator('input[type="search"]'));
    await expect(searchBox.first()).toBeVisible(); // [AI-HEAL] Use .first() to avoid ambiguous multi-match locators
    await searchBox.first().fill('Playwright automation'); // [AI-HEAL] Use .first() for consistency
    console.log('[step] ✅ Filled search box with query');

    // Step 3: Submit search
    await searchBox.first().press('Enter'); // [AI-HEAL] Use .first() for consistency
    await page.waitForLoadState('networkidle');
    console.log('[step] ✅ Submitted search and waited for results');

    // Step 4: Click the first search result
    // [AI-HEAL] Add waitForSelector for timing gap before locating first result
    await page.waitForSelector('main a'); // [AI-HEAL] Wait for at least one link in main content
    // [AI-HEAL] FIX: Use page.locator('main a').first() instead of mixing getByRole('main') and getByRole('link') to avoid "Locators must belong to the same frame"
    const firstResult = page.locator('main a').first(); // [AI-HEAL] Use a single locator chain within the same frame
    await expect(firstResult).toBeVisible();
    try {
      await firstResult.click();
    } catch (e) {
      // [AI-HEAL] Fallback click strategy in case of intercepted click
      await firstResult.evaluate(node => (node as HTMLElement).click());
    }
    await page.waitForLoadState('networkidle');
    console.log('[step] ✅ Clicked first search result');

    // Step 5: Verify article heading is present
    // [AI-HEAL] Add waitForSelector for heading to handle dynamic loading
    await page.waitForSelector('h1'); // [AI-HEAL] Wait for heading to appear
    const heading = page.locator('h1').first(); // [AI-HEAL] Use page.locator('h1').first() instead of getByRole('heading', { level: 1 }) to ensure locator is in the same frame and avoid "Locators must belong to the same frame"
    await expect(heading).toBeVisible();
    console.log('[step] ✅ Verified article heading is visible');

    // Step 6: Check for Table of Contents section
    // [AI-HEAL] Use .or() to provide alternative selector chains for dynamic TOC region
    const tocRegion = page.locator('#toc')
      .or(() => page.locator('nav[aria-label*="Contents" i]'))
      .or(() => page.locator('[role="region"][aria-label*="contents" i]'))
      .or(() => page.locator('[role="navigation"][aria-label*="contents" i]'))
      .or(() => page.locator('h2:has-text("Contents")')); // [AI-HEAL] Use only locator chains to ensure all locators are in the same frame and avoid "Locators must belong to the same frame"
    await expect(tocRegion.first()).toBeVisible(); // [AI-HEAL] Use .first() to avoid ambiguity
    console.log('[step] ✅ Verified Table of Contents is visible');
  });
});
